import{_ as e,c as i,o as l,ae as t}from"./chunks/framework.Dh1jimFm.js";const h=JSON.parse('{"title":"HTML标签","description":"","frontmatter":{},"headers":[],"relativePath":"document/HtmlTag.md","filePath":"document/HtmlTag.md"}'),s={name:"document/HtmlTag.md"};function n(o,a,p,c,r,u){return l(),i("div",null,a[0]||(a[0]=[t(`<h1 id="html标签" tabindex="-1">HTML标签 <a class="header-anchor" href="#html标签" aria-label="Permalink to &quot;HTML标签&quot;">​</a></h1><h2 id="html标签类型" tabindex="-1">HTML标签类型 <a class="header-anchor" href="#html标签类型" aria-label="Permalink to &quot;HTML标签类型&quot;">​</a></h2><ul><li>行内元素：不能设置宽高 宽高由内容决定，常见：a、b、span、strong</li><li>块级元素：可设置宽高内外边距、独占一行，常见：div、ul、li、dl、dt、h1-5、p</li><li>行内块元素：可以设置宽高内外边距，常见：img、input、td</li><li>空元素：没有对应的闭合标签，常见：br、hr、link、meta</li><li>通过css的display属性可以切换行内元素/inline、行内块元素/inline-block、块元素/block</li></ul><h2 id="语义化标签" tabindex="-1">语义化标签 <a class="header-anchor" href="#语义化标签" aria-label="Permalink to &quot;语义化标签&quot;">​</a></h2><p>概念：语义化是指根据内容的结构化、语义化，选择合适的标签（代码语义化），便于开发者阅读和写出更优雅的代码，同时让浏览器的爬虫和机器更好的解析</p><p>语义化的好处：</p><ul><li>用正确的标签做正确的事情</li><li>样式丢失或加载不到时使页面呈现出清晰的结构</li><li>方便其他设备解析（如：屏幕阅读器、盲人阅读器、移动设备等），</li><li>有利于SEO：和搜索引擎建立良好沟通，有助于爬虫抓取更多的有效信息，爬虫依赖于标签来确定上下文和各个关键字的权重</li><li>有利于团队开发和维护，语义化更具可读性，遵循W3C标准的团队都遵循这个写法，可以减少差异化</li></ul><h2 id="a标签的作用" tabindex="-1">a标签的作用 <a class="header-anchor" href="#a标签的作用" aria-label="Permalink to &quot;a标签的作用&quot;">​</a></h2><ul><li>打开新页面（外部页面链接），跳转到不同url链接，target属性有一下值： <ul><li>_self 在当前页面打开链接</li><li>_blank 在新窗口打开链接</li><li>_top 在顶层窗口打开链接</li></ul></li><li>锚点，跳转到页面指定位置</li><li>下载文件，下载的原理在于a标签所对应的资源浏览器无法解析时，会将其下载下来</li><li>手机拨号</li><li>发送短信</li><li>发送邮件</li></ul><h2 id="input标签的type属性" tabindex="-1">input标签的type属性 <a class="header-anchor" href="#input标签的type属性" aria-label="Permalink to &quot;input标签的type属性&quot;">​</a></h2><p>| 属性值 | 描述 | | text | 默认。定义单行输入字段，用户可在其中输入文本，默认20个字符 | | button | 定义可点击按钮 | | radio | 定义单选框 | | checkbox | 定义复选框 | | file | 定义输入字段和“浏览”按钮，供文件上传 | | hidden | 定义隐藏输入字段 | | image | 定义图像作为提交按钮 | | password | 定义密码字段，其中的字符会被遮盖 | | reset | 定义充值按钮，重置按钮会将所有表单字段重置为初始值 | | submit | 定义提交按钮，提交按钮向服务器发送数据 | | url | 定义用于URL的文本字段 | | H5新增 | 以下为H5新增 | | color | 定义拾色器 | | date | 定义日期字段 （带有calendar空间） | | datetime | 定义日期字段（带有calendar 和 time 控件） | | datetime-local | 定义日期字段（带有calendar 和 time 控件） | | month | 定义日期字段的月（带有calendar 控件） | | week | 定义日期字段的周（带有calendar 控件） | | time | 定义日期字段的时、分、秒（带有calendar 控件） | | email | 用于定义e-mail地址的文本字段 | | number | 定义带有 spinner 控件的数字字段 | | range | 定义带有slider控件的数字字段 | | search | 定义用于搜索的文本字段 | | tel | 定义用于电话号码的文本字段 |</p><h2 id="iframe标签" tabindex="-1">iframe标签 <a class="header-anchor" href="#iframe标签" aria-label="Permalink to &quot;iframe标签&quot;">​</a></h2><p>html标签，作用是文档中的文档，嵌入式框架，用来在页面中嵌入其它页面</p><ul><li>优点： <ul><li>还原性：iframe能够原封不动的把嵌入的网页展现出来</li><li>模块化：如果有多个网页引用iframe，只需要修改frame的内容，就可以实现每个调用页面中内容的更改-方便快捷</li><li>可复用：统一网页风格，并用iframe来嵌套，可实现-码复用</li><li>iframe可以跨域通信</li><li>解决了加载缓慢的第三方内容如图标和广告等加载问题</li><li>用于微前端架构，分拆大型项目</li></ul></li><li>缺点： <ul><li>阻塞主页面的onload事件</li><li>搜索引擎无法检索iframe页面，不利于SEO</li><li>兼容性较差，ie11开始支持</li></ul></li></ul><h2 id="label标签" tabindex="-1">label标签 <a class="header-anchor" href="#label标签" aria-label="Permalink to &quot;label标签&quot;">​</a></h2><p>label标签为 input 元素定义标签，本身不会有任何特殊样式，并为鼠标用户改善了可用性，当用户点击label元素内的文本时，会聚焦到表单控件本身</p><h2 id="meta标签" tabindex="-1">meta标签 <a class="header-anchor" href="#meta标签" aria-label="Permalink to &quot;meta标签&quot;">​</a></h2><p>meta标签由name和content属性定义，用来描述网页文档的属性，比如网页的作者、网页的描述、关键词等，除了HTTP标准固定了一些name代表具体含义外，开发者还可以自定义name</p><p>常用的meta标签：</p><ul><li>charset 用来描述HTML文档的编码类型</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;meta charset=&quot;UTF-8&quot; &gt;</span></span></code></pre></div><ul><li>keywords 页面关键词</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;meta name=&quot;keywords&quot; content=&quot;关键词&quot; /&gt;</span></span></code></pre></div><ul><li>description 页面描述</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;meta http-equiv=&quot;refresh&quot; content=&quot;0;url=&quot; /&gt;</span></span></code></pre></div><ul><li>refresh 页面重定向和刷新</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;meta http-equiv=&quot;refresh&quot; content=&quot;0;url=&quot; /&gt;</span></span></code></pre></div><ul><li>viewport 适配移动端，可控制饰扣大小和比例</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1, maximum-scale=1&quot;&gt;</span></span></code></pre></div><p>content参数有以下几种：</p><ul><li>width viewport ：宽度(数值/device-width)</li><li>height viewport ：高度(数值/device-height)</li><li>initial-scale ：初始缩放比例</li><li>maximum-scale ：最大缩放比例</li><li>minimum-scale ：最小缩放比例</li><li>user-scalable ：是否允许用户缩放(yes/no）</li></ul><p>搜索引擎索引方式：<code>&lt;meta name=&quot;robots&quot; content=&quot;index,follow&quot; /&gt;</code> 其中content参数有以下几种：</p><ul><li>all：文件将被检索，且页面上的链接可以被查询；</li><li>none：文件将不被检索，且页面上的链接不可以被查询；</li><li>index：文件将被检索；</li><li>follow：页面上的链接可以被查询；</li><li>noindex：文件将不被检索；</li><li>nofollow：页面上的链接不可以被查询；</li></ul><h2 id="img标签" tabindex="-1">img标签 <a class="header-anchor" href="#img标签" aria-label="Permalink to &quot;img标签&quot;">​</a></h2><p>srcset属性用于响应式页面中根据屏幕密度设置不同图片</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;img src=&quot;image-128.png&quot; srcset=&quot;image-256.png 2x&quot; /&gt;</span></span></code></pre></div><p>使用上面的代码，就能实现在屏幕密度为1x的情况下加载image-128.png, 屏幕密度为2x时加载image-256.png。 按照上面的实现，不同的屏幕密度都要设置图片地址，目前的屏幕密度有1x,2x,3x,4x四种，如果每一个图片都设置4张图片，加载就会很慢。所以就有了新的srcset标准。代码如下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;img src=&quot;image-128.png&quot;</span></span>
<span class="line"><span>     srcset=&quot;image-128.png 128w, image-256.png 256w, image-512.png 512w&quot;</span></span>
<span class="line"><span>     sizes=&quot;(max-width: 360px) 340px, 128px&quot; /&gt;</span></span></code></pre></div><p>其中srcset指定图片的地址和对应的图片质量。sizes用来设置图片的尺寸零界点。对于 srcset 中的 w 单位，可以理解成图片质量。如果可视区域小于这个质量的值，就可以使用。浏览器会自动选择一个最小的可用图片。</p>`,39)]))}const m=e(s,[["render",n]]);export{h as __pageData,m as default};
